# Function to get chapter by book name and language
def get_bible_chapter(book: str, chapter: int, lang: str = "it") -> list:
    """Get verses for a specific chapter"""
    key = f"{book}:{chapter}"
    
    if lang == "it":
        return NUOVA_DIODATI.get(key, [])
    elif lang == "es":
        return REINA_VALERA_1960.get(key, [])
    
    # Try to find equivalent in Italian first
    return NUOVA_DIODATI.get(key, [])
